import{_ as r,o as t,c as o,a3 as i}from"./chunks/framework.BsQeBrPm.js";const c=JSON.parse('{"title":"交易・交易ルートガイド","description":"","frontmatter":{},"headers":[],"relativePath":"guide/trade-guide.md","filePath":"guide/trade-guide.md"}'),n={name:"guide/trade-guide.md"};function s(a,l,g,e,h,u){return t(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="交易・交易ルートガイド" tabindex="-1">交易・交易ルートガイド <a class="header-anchor" href="#交易・交易ルートガイド" aria-label="Permalink to &quot;交易・交易ルートガイド&quot;">​</a></h1><blockquote><p>このページはインターネット上の攻略情報を集約した内容です。未検証の情報を含む場合があります。</p></blockquote><hr><h2 id="交易の全体像" tabindex="-1">交易の全体像 <a class="header-anchor" href="#交易の全体像" aria-label="Permalink to &quot;交易の全体像&quot;">​</a></h2><p>Anno 117 の交易には大きく2種類あります。</p><ul><li><strong>能動的交易（交易ルート）</strong>: 自分の船を使い、島と島（および地域間）を巡回させて商品を自動で積み下ろしします。自分の島同士でも、NPC（他都市）相手でも設定可能です。</li><li><strong>受動的交易</strong>: 交易所の各商品に「売り設定・買い設定」を設定しておくと、交易協定を結んだ相手やNPC商人が自動で船を寄越して取引します。手動管理がほぼ不要です。</li></ul><hr><h2 id="交易ルートの設定手順-能動的交易" tabindex="-1">交易ルートの設定手順（能動的交易） <a class="header-anchor" href="#交易ルートの設定手順-能動的交易" aria-label="Permalink to &quot;交易ルートの設定手順（能動的交易）&quot;">​</a></h2><ol><li>画面下部のHUDから<strong>交易ルートメニュー</strong>を開く。アイコンは「2本の矢印」。</li><li>「<strong>新規交易ルート</strong>」を選択。</li><li>**1つ目の島（出発地）**を選ぶ。</li><li>**2つ目の島（目的地）**を選ぶ。3島以上を順に追加することも可能。</li><li>ルートに使う<strong>船を割り当てる</strong>。</li><li>各島で<strong>積む商品／下ろす商品</strong>を設定する。商品ごとに<strong>カーゴスロット</strong>を割り当てる。</li><li>「<strong>確定</strong>」でルートを起動。以後、船がルートを<strong>ループ巡回</strong>し自動で積み下ろしします。</li></ol><h3 id="地域をまたぐルート-ラティウム-⇄-アルビオン" tabindex="-1">地域をまたぐルート（ラティウム ⇄ アルビオン） <a class="header-anchor" href="#地域をまたぐルート-ラティウム-⇄-アルビオン" aria-label="Permalink to &quot;地域をまたぐルート（ラティウム ⇄ アルビオン）&quot;">​</a></h3><ul><li>基本手順は同じですが、島を選ぶ際に<strong>地域マップを切り替える</strong>必要があります。</li><li>出発地・目的地は異なる地域でも指定できます。</li></ul><hr><h2 id="受動的交易-売買注文" tabindex="-1">受動的交易（売買注文） <a class="header-anchor" href="#受動的交易-売買注文" aria-label="Permalink to &quot;受動的交易（売買注文）&quot;">​</a></h2><p>交易所・港のメニューで各商品に閾値を設定します。</p><ul><li><strong>最低在庫</strong>: 常に島に残しておく量。これ以下は売らない。</li><li><strong>上限値</strong>: この量を超えると自動で売却を開始する。</li><li><strong>下限値</strong>: この値を下回ると商品を、上限まで自動で買い付ける。</li><li>交易協定を結んだ相手は、<strong>定期的に船を寄港</strong>して売買してくれます。</li></ul><hr><h2 id="価格・収益の注意" tabindex="-1">価格・収益の注意 <a class="header-anchor" href="#価格・収益の注意" aria-label="Permalink to &quot;価格・収益の注意&quot;">​</a></h2><ul><li>各商品には<strong>金銭価値に基づく単価</strong>があり、メニュー上のアイコンに表示されます。</li><li>受動的交易の単価は控えめです。</li><li>NPCは余剰生産を勝手に買い取らない。<strong>売り設定を能動的に行う必要</strong>があります。</li><li>NPCは<strong>自分が不足している商品のみ</strong>購入します。</li><li>ゲーム設計上、過剰生産での輸出は労働者コストに見合わないことが多く、<strong>輸出特化より自分の都市の需要に合わせた生産</strong>が推奨されます。</li><li>生産過剰により住民の消費が止まるより、売却して経済を回すほうが有益な場合もあります。</li></ul><hr><h2 id="船の選択とカーゴ・速度" tabindex="-1">船の選択とカーゴ・速度 <a class="header-anchor" href="#船の選択とカーゴ・速度" aria-label="Permalink to &quot;船の選択とカーゴ・速度&quot;">​</a></h2><ul><li><strong>民間船</strong>: カーゴスロットが多く、輸送量に優れます。</li><li><strong>軍用船</strong>: 攻撃を受けても自衛できます。海賊・敵対勢力対策。</li><li>船は3ティア構成: <strong>ペンテコンター → トライリーメ → クィンクェレメ</strong>。民間・軍団それぞれ存在します。</li><li>長距離・大量輸送には<strong>五段櫂船</strong>を推奨。最良の積載量と耐久力を持ちます。 <ul><li>カーゴスロットは<strong>最大7スロット</strong>（積み下ろし専用3スロット＋モジュール用4スロット）。</li><li><strong>マスト</strong>を装備すると風向きによるが<strong>最大速度</strong>が向上。</li><li><strong>オール</strong>を装備すると<strong>風向きによる影響</strong>が減少。</li><li><strong>船体装甲</strong>は船の<strong>耐久力</strong>を高める。</li></ul></li><li>船の建造は<strong>造船所</strong>が必要で、木板・ロープ・帆・防具・武器などが必要です。</li><li>高ティア船ほど<strong>モジュール</strong>を多く装着でき、速度増加や弓兵・バリスタによる防御などを付与できます。</li><li>**専門家（船長）**を船に乗せると交戦力・交易コスト削減など様々な効果を得られます。</li></ul><hr><h2 id="npc・他都市との売買-交易協定・外交" tabindex="-1">NPC・他都市との売買（交易協定・外交） <a class="header-anchor" href="#npc・他都市との売買-交易協定・外交" aria-label="Permalink to &quot;NPC・他都市との売買（交易協定・外交）&quot;">​</a></h2><h3 id="交易協定の締結" tabindex="-1">交易協定の締結 <a class="header-anchor" href="#交易協定の締結" aria-label="Permalink to &quot;交易協定の締結&quot;">​</a></h3><ul><li>NPC（ライバル）と取引するにはまず<strong>交易協定</strong>を結ぶ必要があります。</li><li>協定は<strong>相手との関係を改善</strong>してから利用可能になります。改善手段: <ul><li><strong>クエストの達成</strong></li><li><strong>金銭の贈与</strong></li><li><strong>島の契約の履行</strong></li><li><strong>NPC固有のステータスの達成率</strong></li></ul></li><li>協定締結後、新規交易ルートを設定でき、受動的な売買注文も相手の市場に対して有効化されます。</li></ul><h3 id="取引相手のキャラクターと商品-例" tabindex="-1">取引相手のキャラクターと商品（例） <a class="header-anchor" href="#取引相手のキャラクターと商品-例" aria-label="Permalink to &quot;取引相手のキャラクターと商品（例）&quot;">​</a></h3><p>各キャラは「売りたい商品」と「欲しい商品」を持ちます。例:</p><ul><li><strong>ドリアン</strong> は <strong>大理石／アンフォラ／靴</strong> を売り、<strong>チーズ／石鹸／オリーブオイル</strong> を求める。</li><li>ドリアンに <strong>オリーブオイル／石鹸／ガルム</strong> を売ると、進行に従い最大100個・<strong>60〜74/個</strong>で買い取り、良い収入源になります。</li><li>緊急時には船に余剰を積み、NPC（商人）に直接売って即時資金化できます。</li><li>NPC（商人）には無制限に購入してくれる商品があります。</li></ul><h3 id="外交システム全体" tabindex="-1">外交システム全体 <a class="header-anchor" href="#外交システム全体" aria-label="Permalink to &quot;外交システム全体&quot;">​</a></h3><ul><li>NPCライバルを最大3名選択可能。例: <strong>ドリアン</strong>（健康・文化重視、ラティウムのみ入植、平和志向）、<strong>タラゴン</strong>（軍人気質）、<strong>コンクロディア</strong>（宗教・ローマ伝統重視、拡張志向）、<strong>アーサー</strong>（アルビオンのケルト系の統治者）。</li><li>外交メニューでは各ライバルの<strong>治世状況・条約状況・軍事力/経済力/契約履行・キャラ特性</strong>などを確認できます。</li><li>取れる外交アクション: <ul><li><strong>交易協定</strong> — 港での商品売買</li><li><strong>防衛協定</strong> — 相互防衛</li><li><strong>同盟</strong> — 友好・支援</li><li><strong>贈り物（大/小） / 専門家任命</strong>（研究が必要）</li></ul></li><li><strong>従属化（属国化）</strong>: 同盟状態で相手より強いこと、執政官（執政官代理）の役職を持ち相手を上回る資金（ただし超高額）があると、ライバルを<strong>属国化</strong>できます。従属したライバルは強力な専門家として自分の総督のヴィラに配置でき、その島は属国都市になります。</li><li><strong>戦争</strong>: 全面戦争（皇帝の協力を買う）と限定戦争（民間建物と交易ルートを保護）があります。戦争宣言は<strong>皇帝への評判を低下</strong>させ、評判が低いほど皇帝が介入しやすくなります。</li><li><strong>皇帝との関係</strong>: 皇帝の要望・行動選択などにより増減し、入植コスト・島の維持費の増減・NPC商人との交易の有無・執政官（執政官代理）の称号取得に影響します。</li></ul><hr><h2 id="交易所・港のアップグレード-研究" tabindex="-1">交易所・港のアップグレード（研究） <a class="header-anchor" href="#交易所・港のアップグレード-研究" aria-label="Permalink to &quot;交易所・港のアップグレード（研究）&quot;">​</a></h2><p>交易効率を高める主な研究技術:</p><ul><li><strong>貯蔵所</strong>: 島の保管容量を増やす。</li><li><strong>交易所改良</strong>: クレーンを追加し積み下ろしを高速化。島の保管容量を増やす。</li><li><strong>交易埠頭</strong>: 沿岸に配置し積み下ろしができる。航路の距離を短縮できて便利。</li><li><strong>港湾指定</strong>: 終盤技術。どの船がどの交易所/交易埠頭を使うか指定できる。</li><li><strong>修理クレーン</strong>: 港で交易船・軍用船を修理。</li></ul><h3 id="交易に有用な信仰神" tabindex="-1">交易に有用な信仰神 <a class="header-anchor" href="#交易に有用な信仰神" aria-label="Permalink to &quot;交易に有用な信仰神&quot;">​</a></h3><ul><li><strong>ネプトゥーヌス</strong>: 序盤向け。新造船の維持費削減・耐久増加・海産物に関する生産チェーンを強化。</li><li><strong>メルクリウス＝ルグス</strong>: 終盤向け。<strong>受動的交易の収益と、港/交易所からの名声を強化</strong>。受動交易をより儲かるようにします。</li></ul><hr><h2 id="交易ルート運用のコツ" tabindex="-1">交易ルート運用のコツ <a class="header-anchor" href="#交易ルート運用のコツ" aria-label="Permalink to &quot;交易ルート運用のコツ&quot;">​</a></h2><ul><li><strong>ルート明確化</strong>: 島の名前を変える（例: 「樹脂島」「オリーブ島」）。ルート把握が容易になります。</li><li><strong>輸出量の調整（往復時間を考慮）</strong>: <ul><li>近い島: 消費量より <strong>2〜3トン</strong>多く生産・輸出。</li><li>遠い島: 消費が <strong>10トン/分</strong> なら、往復時間を見込み <strong>約15〜16トン/分</strong>の積み込み。</li><li>最低在庫は低め（<strong>50〜100単位</strong>）に設定し余剰を輸出に回す。</li></ul></li><li><strong>ルートの防衛</strong>: <ul><li>護衛 — 交易船と<strong>同速度</strong>の軍船を割り当て。</li><li>巡回 — 島間に軍船を配置し即応。</li><li>迂回 — 海賊多発海域を避けてルート変更。</li></ul></li><li><strong>よくある航路の問題</strong>: <ul><li>容量がいっぱいで荷下ろしできない。</li><li>在庫がゼロで積み込みできない。</li><li>内容だけ変更して以前の荷物が下ろせていない。</li><li>船が攻撃を受けて損傷・沈没し機能していない。</li></ul></li></ul>',39)])])}const b=r(n,[["render",s]]);export{c as __pageData,b as default};
